 1	import { type FC, useMemo } from 'react';
 2	import { loadUserSettings } from 'src/components/common/Page/userSettings';
 3	import StandardPage from 'src/components/page/StandardPage';
 4	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { INITIAL_PAGE } from '@components/page/utils/constants';
 8	import { PlanModel, PlanModelGroupVersionKind, type V1beta1Plan } from '@kubev2v/types';
 9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
10	
11	import PlanRow from './components/PlanRow/PlanRow';
12	import PlansAddButton from './components/PlansAddButton';
13	import PlansEmptyState from './components/PlansEmptyState';
14	import { PlanTableResourceId } from './utils/constants';
15	import { planFields } from './utils/planFields';
16	
17	import './PlansListPage.style.css';
18	
19	type PlansListPageProps = {
20	  namespace: string;
21	};
22	
23	const PlansListPage: FC<PlansListPageProps> = ({ namespace }) => {
24	  const { t } = useForkliftTranslation();
25	
26	  const userSettings = useMemo(() => loadUserSettings({ pageId: 'Plans' }), []);
27	
28	  const [plans, plansLoaded, plansLoadError] = useK8sWatchResource<V1beta1Plan[]>({
29	    groupVersionKind: PlanModelGroupVersionKind,
30	    isList: true,
31	    namespace,
32	    namespaced: true,
33	  });
34	
35	  const { canCreate } = useGetDeleteAndEditAccessReview({
36	    model: PlanModel,
37	    namespace,
38	  });
39	
40	  return (
41	    <StandardPage
42	      data-testid="plans-list"
43	      addButton={
44	        <PlansAddButton testId="create-plan-button" namespace={namespace} canCreate={canCreate} />
45	      }
46	      dataSource={[plans || [], plansLoaded, plansLoadError]}
47	      RowMapper={PlanRow}
48	      fieldsMetadata={planFields}
49	      namespace={namespace}
50	      title={t('Migration plans')}
51	      titleHelpContent={t(
52	        'A migration plan is a strategy for moving VMs from 1 environment to OpenShift Virtualization. It lets you group VMs to be migrated together or with the same migration configuration.',
53	      )}
54	      userSettings={userSettings}
55	      customNoResultsFound={<PlansEmptyState namespace={namespace} />}
56	      page={INITIAL_PAGE}
57	      postFilterData={(data, selectedFilters) =>
58	        selectedFilters[PlanTableResourceId.Archived]?.[0] === 'true'
59	          ? data
60	          : data.filter((plan) => !plan?.spec?.archived)
61	      }
62	    />
63	  );
64	};
65	
66	export default PlansListPage;

